from typing import Protocol, TypeVar, Generic, Optional, List, Any
from datetime import timedelta

T = TypeVar("T")


class CacheProtocol(Generic[T], Protocol):
    async def set(
        self, key: str, value: T, ttl: Optional[timedelta] = None
    ) -> None: ...
    async def get(self, key: str) -> Optional[T]: ...
    async def delete(self, key: str) -> None: ...
    async def all(self) -> List[T]: ...
    async def keys(self) -> List[str]: ...
    async def temporary_set(self, key: str | int, ttl: timedelta, **kwargs) -> None: ...
    async def temporary_get(self, key: str | int) -> Any: ...
